#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=2e6+5;
int n,d,s[maxn],q[maxn],p;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>p>>d;
	s[0]=0;
	for(int i=1; i<=n; i++) {
		int x;
		cin>>x;
		s[i]=s[i-1]+x;
	}
	int h=1,t=0,l=1,ans=0;
	for(int r=1; r<=n; r++) {
		if(r>=d) {
			int val=s[r]-s[r-d];
			while(h<=t) {
				int k=q[t];
				if((s[k]-s[k-d])<=val) {
					t--;
				} else {
					break;
				}
			}
			q[++t]=r;
		}
		while(r-l+1>d) {
			while(h<=t&&q[h]<(l+d-1)) {
				h++;
			}
			int k=q[h];
			int maxd=s[k]-s[k-d];
			int cost=s[r]-s[l-1]-maxd;
			if(cost>p) {
				l++;
			} else {
				break;
			}
		}
		ans=max(ans,r-l+1);
	}
	cout<<ans;
	return 0;
}
